/** Đổi khi bắt đầu/ hoàn thành từng lô viết lại DIEU_KIEN XML130 (đồng bộ manifest). */
export const CHUYEN_DE_XML130_CONVERSION_VERSION = '2026-04-26-chuyen-de-166-tt22-m01';

/**
 * Điều kiện luôn sai trên hồ sơ có MA_LK — giữ chỗ khi chưa viết được biểu thức XML130/handler.
 * Quy tắc dùng hằng này phải nằm trong danh sách tự động `scripts/chuyen_de_placeholder_registry.json`
 * (đồng bộ: `node scripts/sync_chuyen_de_placeholder_registry.mjs`). Không được hiểu là đã triển khai thực chiến.
 * @see tai_lieu/Kiem_soat_placeholder_CHUYEN_DE_XML130.md
 */
export const CHUYEN_DE_XML130_CHO_XU_LY_SAU = 'IS_EMPTY(XML1.MA_LK) && LEN(XML1.MA_LK) > 0';

/** true nếu DIEU_KIEN vẫn là placeholder XML130 (engine bỏ qua, không phát cảnh báo). */
export const laDieuKienChuyenDeXml130Placeholder = (dieuKien) =>
  String(dieuKien ?? '').trim() === CHUYEN_DE_XML130_CHO_XU_LY_SAU;

/**
 * Proxy chuyên đề «thời gian khám chữa bệnh rút gọn» (ngoại trú MA_LOAI_KCB = 1 và NGAY_VAO→NGAY_RA < 10 phút,
 * định dạng ngày giờ XML130: YYYYMMDDHHmm (12 ký tự số liền, ví dụ NGAY_VAO 202603010707, NGAY_RA 202603010838)
 * hoặc YYYYMMDDHHmmss (14 ký tự); DIFF_MINUTES(NGAY_VAO, NGAY_RA) = hiệu thời điểm parse theo giờ–phút, không so trừ chuỗi/số học;
 * NGAY_RA không trước NGAY_VAO (so TO_NUMBER/chuỗi đầy đủ).
 *
 * Chỉ dùng khi quy tắc *cụ thể* cần phạm vi đó, hoặc khi phủ định (!predicate) để tách vùng nội trú/ngoại trú dài
 * (vd. CV266 KT219, CHUYEN_DE-608). Không dùng làm cổng chung cho mọi Chuyen_de_* — mọi hồ sơ vẫn được engine
 * đánh giá đủ các tầng; điều kiện nghiệp vụ nằm ở từng DIEU_KIEN (XML1/XML2/XML3…), không «chỉ chạy khi <10 phút».
 */
const CHUYEN_DE_XML130_NGOAI_TRU_DUOI_10_PHUT =
  "XML1.MA_LOAI_KCB == '1' && !IS_EMPTY(XML1.NGAY_VAO) && !IS_EMPTY(XML1.NGAY_RA) && (LEN(XML1.NGAY_VAO) == 12 || LEN(XML1.NGAY_VAO) == 14) && (LEN(XML1.NGAY_RA) == 12 || LEN(XML1.NGAY_RA) == 14) && TO_NUMBER(XML1.NGAY_RA) >= TO_NUMBER(XML1.NGAY_VAO) && DIFF_MINUTES(XML1.NGAY_VAO, XML1.NGAY_RA) < 10";

/** Có ít nhất một dòng XML3 tên dịch vụ gợi siêu âm (áp Chuyen_de_150). */
